package org.apache.kafka.common.record.internal;

import org.apache.kafka.common.compress.Compression;
import org.apache.kafka.common.errors.CorruptRecordException;
import org.apache.kafka.common.message.KRaftVersionRecord;
import org.apache.kafka.common.message.LeaderChangeMessage;
import org.apache.kafka.common.message.SnapshotFooterRecord;
import org.apache.kafka.common.message.SnapshotHeaderRecord;
import org.apache.kafka.common.message.VotersRecord;
import org.apache.kafka.common.network.TransferableChannel;
import org.apache.kafka.common.record.TimestampType;
import org.apache.kafka.common.record.internal.MemoryRecords.RecordFilter.BatchRetention;
import org.apache.kafka.common.record.internal.MemoryRecords.RecordFilter.BatchRetentionResult;
import org.apache.kafka.common.utils.AbstractIterator;
import org.apache.kafka.common.utils.BufferSupplier;
import org.apache.kafka.common.utils.ByteBufferOutputStream;
import org.apache.kafka.common.utils.CloseableIterator;
import org.apache.kafka.common.utils.Utils;

import java.io.IOException;
import java.nio.ByteBuffer;
import java.nio.channels.GatheringByteChannel;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Objects;

/**
 * An in-memory, {@link ByteBuffer}-backed implementation of {@link Records} that holds one or
 * more serialised {@link RecordBatch}es. This is the primary representation used by Kafka
 * producers, consumers, and the broker's network layer when record data is held in heap memory.
 *
 * <h2>Role in the Kafka protocol</h2>
 * <p>{@code MemoryRecords} sits at the boundary between the network/storage layer and the
 * application layer. Producers build instances via {@link MemoryRecordsBuilder} (or the
 * {@link #builder} factory methods) and send them to the broker. The broker receives them,
 * optionally mutates batch metadata in place (e.g., assigning log offsets and log-append
 * timestamps via {@link MutableRecordBatch}), and appends them to the partition log. Consumers
 * receive {@code MemoryRecords} instances from the broker and iterate over the contained
 * {@link RecordBatch}es and {@link Record}s.
 *
 * <h2>Construction</h2>
 * <p>There are two ways to obtain a {@code MemoryRecords} instance:
 * <ol>
 *   <li><b>Reading an existing buffer:</b> Use {@link #readableRecords(ByteBuffer)} to wrap a
 *       buffer that already contains encoded batch data. The buffer is not copied; the
 *       {@code MemoryRecords} instance holds a reference to it.</li>
 *   <li><b>Building a new batch:</b> Use one of the {@link #builder} factory methods to obtain
 *       a {@link MemoryRecordsBuilder}, append records to it, and call
 *       {@link MemoryRecordsBuilder#build()} to produce the final {@code MemoryRecords}. The
 *       convenience {@code withRecords}, {@code withIdempotentRecords},
 *       {@code withTransactionalRecords}, and {@code withEndTransactionMarker} methods combine
 *       these steps into a single call.</li>
 * </ol>
 *
 * <h2>Performance characteristics</h2>
 * <ul>
 *   <li>Batch iteration ({@link #batches()}, {@link #batchIterator()}) is zero-copy: each
 *       {@link MutableRecordBatch} is a lightweight view over a slice of the backing buffer.</li>
 *   <li>Record iteration ({@link Records#records()}) may require decompression. Use
 *       {@link RecordBatch#streamingIterator(BufferSupplier)} with a pooling
 *       {@link BufferSupplier} to amortise decompression buffer allocation costs.</li>
 *   <li>{@link #validBytes()} is computed lazily on first call and then cached; subsequent
 *       calls are O(1).</li>
 *   <li>{@link #filterTo(RecordFilter, ByteBuffer, BufferSupplier)} performs record-level
 *       filtering in a single pass and writes the retained records directly into the supplied
 *       destination buffer, avoiding an extra copy.</li>
 *   <li>{@link #slice(int, int)} returns a zero-copy view backed by the same underlying bytes.</li>
 * </ul>
 *
 * <p><b>Thread safety:</b> Instances of this class are <em>not</em> thread-safe. The backing
 * {@link ByteBuffer} is shared by reference, and concurrent reads or writes (including the
 * in-place mutations performed by {@link MutableRecordBatch} methods) require external
 * synchronisation.
 *
 * @see RecordBatch
 * @see DefaultRecordBatch
 * @see MemoryRecordsBuilder
 * @see Records
 */
public class MemoryRecords extends AbstractRecords {
    /** A singleton empty {@code MemoryRecords} instance backed by a zero-capacity buffer. */
    public static final MemoryRecords EMPTY = MemoryRecords.readableRecords(ByteBuffer.allocate(0));

    private final ByteBuffer buffer;

    private final Iterable<MutableRecordBatch> batches = this::batchIterator;

    private int validBytes = -1;

    // Construct a writable memory records
    private MemoryRecords(ByteBuffer buffer) {
        Objects.requireNonNull(buffer, "buffer should not be null");
        this.buffer = buffer;
    }

    /**
     * Return the total number of bytes in the backing buffer, including any partial or trailing
     * batches that may not be parseable.
     *
     * <p>This value equals the limit of the underlying {@link ByteBuffer} and is O(1). To
     * obtain the number of bytes belonging to complete, valid batches only, use
     * {@link #validBytes()}.
     *
     * @return The total number of bytes in the backing buffer
     */
    @Override
    public int sizeInBytes() {
        return buffer.limit();
    }

    /**
     * Write a contiguous region of this record set to the given {@link TransferableChannel}.
     *
     * <p>This method delegates to {@link Utils#tryWriteTo} and may perform a partial write if
     * the channel is non-blocking. The caller is responsible for retrying until all bytes have
     * been transferred.
     *
     * @param channel  The channel to write to; must not be {@code null}
     * @param position The byte offset within this record set at which to start writing;
     *                 must be non-negative and satisfy {@code position + length <= sizeInBytes()}
     * @param length   The number of bytes to write; must be non-negative
     * @return The number of bytes actually written in this call, which may be less than
     *         {@code length} for non-blocking channels
     * @throws IllegalArgumentException if {@code position + length} exceeds
     *                                  {@link #sizeInBytes()}
     * @throws IOException              if an I/O error occurs while writing to the channel
     */
    @Override
    public int writeTo(TransferableChannel channel, int position, int length) throws IOException {
        if (((long) position) + length > buffer.limit())
            throw new IllegalArgumentException("position+length should not be greater than buffer.limit(), position: "
                    + position + ", length: " + length + ", buffer.limit(): " + buffer.limit());

        return Utils.tryWriteTo(channel, position, length, buffer);
    }

    /**
     * Write all records to the given channel (including partial records).
     * @param channel The channel to write to
     * @return The number of bytes written
     * @throws IOException For any IO errors writing to the channel
     */
    public int writeFullyTo(GatheringByteChannel channel) throws IOException {
        buffer.mark();
        int written = 0;
        while (written < sizeInBytes())
            written += channel.write(buffer);
        buffer.reset();
        return written;
    }

    /**
     * The total number of bytes in this message set not including any partial, trailing messages. This
     * may be smaller than what is returned by {@link #sizeInBytes()}.
     *
     * <p>The result is computed lazily on the first call by iterating over all complete batches
     * and summing their sizes. The computed value is cached so that subsequent calls are O(1).
     *
     * @return The number of valid bytes
     */
    public int validBytes() {
        if (validBytes >= 0)
            return validBytes;

        int bytes = 0;
        for (RecordBatch batch : batches())
            bytes += batch.sizeInBytes();

        this.validBytes = bytes;
        return bytes;
    }

    /**
     * Return an {@link AbstractIterator} over the {@link MutableRecordBatch}es in this record
     * set.
     *
     * <p>Each call creates a new iterator that reads from a duplicate of the backing buffer,
     * so multiple iterators can be active concurrently without interfering with each other's
     * position state. The iterator stops at the first incomplete or unparseable batch.
     *
     * @return A new iterator over the mutable record batches; never {@code null}
     */
    @Override
    public AbstractIterator<MutableRecordBatch> batchIterator() {
        return new RecordBatchIterator<>(new ByteBufferLogInputStream(buffer.duplicate(), Integer.MAX_VALUE));
    }

    /**
     * Validates the header of the first batch and returns batch size.
     * @return first batch size including LOG_OVERHEAD if buffer contains header up to
     *         magic byte, null otherwise
     * @throws CorruptRecordException if record size or magic is invalid
     */
    public Integer firstBatchSize() {
        if (buffer.remaining() < HEADER_SIZE_UP_TO_MAGIC)
            return null;
        return new ByteBufferLogInputStream(buffer, Integer.MAX_VALUE).nextBatchSize();
    }

    /**
     * Filter the records into the provided ByteBuffer.
     *
     * @param filter                      The filter function
     * @param destinationBuffer           The byte buffer to write the filtered records to
     * @param decompressionBufferSupplier The supplier of ByteBuffer(s) used for decompression if supported. For small
     *                                    record batches, allocating a potentially large buffer (64 KB for LZ4) will
     *                                    dominate the cost of decompressing and iterating over the records in the
     *                                    batch. As such, a supplier that reuses buffers will have a significant
     *                                    performance impact.
     * @return A FilterResult with a summary of the output (for metrics) and potentially an overflow buffer
     */
    public FilterResult filterTo(RecordFilter filter, ByteBuffer destinationBuffer, BufferSupplier decompressionBufferSupplier) {
        return filterTo(batches(), filter, destinationBuffer, decompressionBufferSupplier);
    }

    /**
     * Note: This method is also used to convert the first timestamp of the batch (which is usually the timestamp of the first record)
     * to the delete horizon of the tombstones or txn markers which are present in the batch.
     */
    private static FilterResult filterTo(Iterable<MutableRecordBatch> batches, RecordFilter filter,
                                         ByteBuffer destinationBuffer, BufferSupplier decompressionBufferSupplier) {
        FilterResult filterResult = new FilterResult(destinationBuffer);
        ByteBufferOutputStream bufferOutputStream = new ByteBufferOutputStream(destinationBuffer);
        for (MutableRecordBatch batch : batches) {
            final BatchRetentionResult batchRetentionResult = filter.checkBatchRetention(batch);
            final boolean containsMarkerForEmptyTxn = batchRetentionResult.containsMarkerForEmptyTxn;
            final BatchRetention batchRetention = batchRetentionResult.batchRetention;

            filterResult.bytesRead += batch.sizeInBytes();

            if (batchRetention == BatchRetention.DELETE)
                continue;

            final BatchFilterResult iterationResult = filterBatch(batch, decompressionBufferSupplier, filterResult,
                filter);
            List<Record> retainedRecords = iterationResult.retainedRecords;
            boolean containsTombstones = iterationResult.containsTombstones;
            boolean writeOriginalBatch = iterationResult.writeOriginalBatch;
            long maxOffset = iterationResult.maxOffset;

            if (!retainedRecords.isEmpty()) {
                // we check if the delete horizon should be set to a new value
                // in which case, we need to reset the base timestamp and overwrite the timestamp deltas
                // if the batch does not contain tombstones, then we don't need to overwrite batch
                boolean needToSetDeleteHorizon = (containsTombstones || containsMarkerForEmptyTxn) &&
                    batch.deleteHorizonMs().isEmpty();
                if (writeOriginalBatch && !needToSetDeleteHorizon) {
                    batch.writeTo(bufferOutputStream);
                    filterResult.updateRetainedBatchMetadata(batch, retainedRecords.size(), false);
                } else {
                    long deleteHorizonMs;
                    if (needToSetDeleteHorizon)
                        deleteHorizonMs = filter.currentTime + filter.deleteRetentionMs;
                    else
                        deleteHorizonMs = batch.deleteHorizonMs().orElse(RecordBatch.NO_TIMESTAMP);
                    try (final MemoryRecordsBuilder builder = buildRetainedRecordsInto(batch, retainedRecords,
                            bufferOutputStream, deleteHorizonMs)) {
                        MemoryRecords records = builder.build();
                        int filteredBatchSize = records.sizeInBytes();
                        MemoryRecordsBuilder.RecordsInfo info = builder.info();
                        filterResult.updateRetainedBatchMetadata(info.maxTimestamp, info.shallowOffsetOfMaxTimestamp,
                            maxOffset, retainedRecords.size(), filteredBatchSize);
                    }
                }
            } else if (batchRetention == BatchRetention.RETAIN_EMPTY) {
                if (batch.magic() < RecordBatch.MAGIC_VALUE_V2) // should never happen
                    throw new IllegalStateException("Empty batches are only supported for magic v2 and above");

                bufferOutputStream.ensureRemaining(DefaultRecordBatch.RECORD_BATCH_OVERHEAD);
                DefaultRecordBatch.writeEmptyHeader(bufferOutputStream.buffer(), RecordBatch.CURRENT_MAGIC_VALUE, batch.producerId(),
                        batch.producerEpoch(), batch.baseSequence(), batch.baseOffset(), batch.lastOffset(),
                        batch.partitionLeaderEpoch(), batch.timestampType(), batch.maxTimestamp(),
                        batch.isTransactional(), batch.isControlBatch());
                filterResult.updateRetainedBatchMetadata(batch, 0, true);
            }

            // If we had to allocate a new buffer to fit the filtered buffer (see KAFKA-5316), return early to
            // avoid the need for additional allocations.
            ByteBuffer outputBuffer = bufferOutputStream.buffer();
            if (outputBuffer != destinationBuffer) {
                filterResult.outputBuffer = outputBuffer;
                return filterResult;
            }
        }

        return filterResult;
    }

    private static BatchFilterResult filterBatch(RecordBatch batch,
                                                 BufferSupplier decompressionBufferSupplier,
                                                 FilterResult filterResult,
                                                 RecordFilter filter) {
        try (final CloseableIterator<Record> iterator = batch.streamingIterator(decompressionBufferSupplier)) {
            long maxOffset = -1;
            boolean containsTombstones = false;
            // Convert records with old record versions
            boolean writeOriginalBatch = batch.magic() >= RecordBatch.CURRENT_MAGIC_VALUE;
            List<Record> retainedRecords = new ArrayList<>();
            while (iterator.hasNext()) {
                Record record = iterator.next();
                filterResult.messagesRead += 1;

                if (filter.shouldRetainRecord(batch, record)) {
                    if (record.offset() > maxOffset)
                        maxOffset = record.offset();

                    retainedRecords.add(record);

                    if (!record.hasValue()) {
                        containsTombstones = true;
                    }
                } else {
                    writeOriginalBatch = false;
                }
            }
            return new BatchFilterResult(retainedRecords, writeOriginalBatch, containsTombstones, maxOffset);
        }
    }

    private static class BatchFilterResult {
        private final List<Record> retainedRecords;
        private final boolean writeOriginalBatch;
        private final boolean containsTombstones;
        private final long maxOffset;
        private BatchFilterResult(List<Record> retainedRecords,
                                  final boolean writeOriginalBatch,
                                  final boolean containsTombstones,
                                  final long maxOffset) {
            this.retainedRecords = retainedRecords;
            this.writeOriginalBatch = writeOriginalBatch;
            this.containsTombstones = containsTombstones;
            this.maxOffset = maxOffset;
        }
    }

    private static MemoryRecordsBuilder buildRetainedRecordsInto(RecordBatch originalBatch,
                                                                 List<Record> retainedRecords,
                                                                 ByteBufferOutputStream bufferOutputStream,
                                                                 final long deleteHorizonMs) {
        Compression compression = Compression.of(originalBatch.compressionType()).build();
        // V0 has no timestamp type or timestamp, so we set the timestamp to CREATE_TIME and timestamp to NO_TIMESTAMP.
        // Note that this differs from produce up-conversion where the timestamp type topic config is used and the log append
        // time is generated if the config is LOG_APPEND_TIME. The reason for the different behavior is that there is
        // no appropriate log append time we can generate at compaction time.
        TimestampType timestampType = originalBatch.timestampType() == TimestampType.NO_TIMESTAMP_TYPE ?
                TimestampType.CREATE_TIME : originalBatch.timestampType();
        long logAppendTime = timestampType == TimestampType.LOG_APPEND_TIME ?
                originalBatch.maxTimestamp() : RecordBatch.NO_TIMESTAMP;
        long baseOffset = originalBatch.magic() >= RecordBatch.MAGIC_VALUE_V2 ?
                originalBatch.baseOffset() : retainedRecords.get(0).offset();

        // Convert records with older record versions to the current one
        MemoryRecordsBuilder builder = new MemoryRecordsBuilder(bufferOutputStream, RecordBatch.CURRENT_MAGIC_VALUE,
                compression, timestampType, baseOffset, logAppendTime, originalBatch.producerId(),
                originalBatch.producerEpoch(), originalBatch.baseSequence(), originalBatch.isTransactional(),
                originalBatch.isControlBatch(), originalBatch.partitionLeaderEpoch(), bufferOutputStream.limit(), deleteHorizonMs);

        for (Record record : retainedRecords)
            builder.append(record);

        if (originalBatch.magic() >= RecordBatch.MAGIC_VALUE_V2)
            // we must preserve the last offset from the initial batch in order to ensure that the
            // last sequence number from the batch remains even after compaction. Otherwise, the producer
            // could incorrectly see an out of sequence error.
            builder.overrideLastOffset(originalBatch.lastOffset());

        return builder;
    }

    /**
     * Get the byte buffer that backs this instance for reading.
     *
     * <p>A duplicate of the underlying buffer is returned so that the caller's position and
     * limit changes do not affect this instance. The returned buffer shares the same backing
     * array (or memory-mapped region) as this instance; modifications to the buffer's content
     * will be visible through this instance.
     *
     * @return A duplicate of the backing {@link ByteBuffer}; never {@code null}
     */
    public ByteBuffer buffer() {
        return buffer.duplicate();
    }

    /**
     * Return a zero-copy slice of this record set starting at the given byte position.
     *
     * <p>The returned {@code MemoryRecords} is backed by the same underlying bytes as this
     * instance (no copy is made). The slice starts at {@code position} and contains at most
     * {@code size} bytes, clamped to the available bytes between {@code position} and the end
     * of this record set.
     *
     * <p>For correct batch iteration, {@code position} should be aligned to a batch boundary.
     * Slicing at an arbitrary byte offset may result in an unparseable leading partial batch.
     *
     * @param position The byte offset within this record set at which the slice begins; must
     *                 be non-negative and not greater than {@link #sizeInBytes()}
     * @param size     The maximum number of bytes to include in the slice; must be non-negative
     * @return A new {@code MemoryRecords} view over the specified region; never {@code null}
     * @throws IllegalArgumentException if {@code position} or {@code size} is negative, or if
     *                                  {@code position} exceeds {@link #sizeInBytes()}
     */
    @Override
    public MemoryRecords slice(int position, int size) {
        if (position < 0)
            throw new IllegalArgumentException("Invalid position: " + position + " in read from " + this);
        if (position > buffer.limit())
            throw new IllegalArgumentException("Slice from position " + position + " exceeds end position of " + this);
        if (size < 0)
            throw new IllegalArgumentException("Invalid size: " + size + " in read from " + this);

        int availableBytes = Math.min(size, buffer.limit() - position);
        // As of now, clients module support Java11 hence can't use ByteBuffer::slice(position, size) method.
        // So we need to create a duplicate buffer and set the position and limit. Duplicate buffer
        // is backed by original bytes hence not the content but only the relative position and limit
        // are changed in the duplicate buffer. Once the position and limit are set, we can call the
        // slice method to get the sliced buffer, which is a backed by the original buffer with the
        // position reset to 0 and limit set to the size of the slice.
        ByteBuffer slicedBuffer = buffer.duplicate();
        slicedBuffer.position(position);
        slicedBuffer.limit(position + availableBytes);
        // Reset the position to 0 so that the sliced view has a relative position.
        slicedBuffer = slicedBuffer.slice();

        return readableRecords(slicedBuffer);
    }

    /**
     * Return an {@link Iterable} over the {@link MutableRecordBatch}es in this record set.
     *
     * <p>The iterable is backed by a fixed reference to {@link #batchIterator()} and can be
     * iterated multiple times. Each iteration creates a new iterator that reads from a
     * duplicate of the backing buffer, so concurrent iterations do not interfere with each
     * other.
     *
     * @return An iterable over the mutable record batches; never {@code null}
     */
    @Override
    public Iterable<MutableRecordBatch> batches() {
        return batches;
    }

    @Override
    public String toString() {
        return "MemoryRecords(size=" + sizeInBytes() +
                ", buffer=" + buffer +
                ")";
    }

    @Override
    public boolean equals(Object o) {
        if (this == o)
            return true;
        if (o == null || getClass() != o.getClass())
            return false;

        MemoryRecords that = (MemoryRecords) o;

        return buffer.equals(that.buffer);
    }

    @Override
    public int hashCode() {
        return buffer.hashCode();
    }

    /**
     * A predicate applied to each {@link RecordBatch} and {@link Record} during a
     * {@link MemoryRecords#filterTo} pass. Implementations decide which batches and records to
     * retain in the output.
     *
     * <p>The filter is first applied at the batch level via
     * {@link #checkBatchRetention(RecordBatch)}. Only batches that are not immediately
     * discarded ({@link BatchRetention#DELETE}) are then examined record by record via
     * {@link #shouldRetainRecord(RecordBatch, Record)}.
     */
    public abstract static class RecordFilter {
        /** The current wall-clock time in milliseconds, used to evaluate time-based retention. */
        public final long currentTime;
        /** The configured delete-retention period in milliseconds. */
        public final long deleteRetentionMs;

        public RecordFilter(final long currentTime, final long deleteRetentionMs) {
            this.currentTime = currentTime;
            this.deleteRetentionMs = deleteRetentionMs;
        }

        /**
         * Encapsulates the result of a batch-level retention check, combining the
         * {@link BatchRetention} decision with a flag indicating whether the batch contains a
         * marker for an empty transaction.
         */
        public static class BatchRetentionResult {
            /** The retention decision for the batch. */
            public final BatchRetention batchRetention;
            /**
             * {@code true} if the batch contains a control record that marks the end of an
             * otherwise empty transaction; {@code false} otherwise.
             */
            public final boolean containsMarkerForEmptyTxn;
            public BatchRetentionResult(final BatchRetention batchRetention,
                                        final boolean containsMarkerForEmptyTxn) {
                this.batchRetention = batchRetention;
                this.containsMarkerForEmptyTxn = containsMarkerForEmptyTxn;
            }
        }

        /**
         * Batch-level retention policy applied before individual records are examined.
         */
        public enum BatchRetention {
            /** Discard the entire batch without inspecting its records. */
            DELETE,
            /** Retain the batch even if all of its records are filtered out. */
            RETAIN_EMPTY,
            /** Discard the batch if it becomes empty after record-level filtering. */
            DELETE_EMPTY
        }

        /**
         * Check whether the full batch can be discarded (i.e. whether we even need to
         * check the records individually).
         *
         * @param batch The batch to evaluate; never {@code null}
         * @return A {@link BatchRetentionResult} containing the retention decision and the
         *         empty-transaction-marker flag; never {@code null}
         */
        protected abstract BatchRetentionResult checkBatchRetention(RecordBatch batch);

        /**
         * Check whether a record should be retained in the log. Note that {@link #checkBatchRetention(RecordBatch)}
         * is used prior to checking individual record retention. Only records from batches which were not
         * explicitly discarded with {@link BatchRetention#DELETE} will be considered.
         *
         * @param recordBatch The batch that contains the record; never {@code null}
         * @param record      The record to evaluate; never {@code null}
         * @return {@code true} if the record should be written to the output; {@code false} if
         *         it should be dropped
         */
        protected abstract boolean shouldRetainRecord(RecordBatch recordBatch, Record record);
    }

    /**
     * Aggregated statistics and output buffer produced by a
     * {@link MemoryRecords#filterTo(RecordFilter, ByteBuffer, BufferSupplier)} pass.
     *
     * <p>The output buffer may differ from the destination buffer passed to {@code filterTo} if
     * the filtered output exceeded the destination buffer's capacity and a larger buffer had to
     * be allocated (see KAFKA-5316). Callers should always use {@link #outputBuffer()} rather
     * than the original destination buffer to access the filtered data.
     */
    public static class FilterResult {
        private ByteBuffer outputBuffer;
        private int messagesRead = 0;
        // Note that `bytesRead` should contain only bytes from batches that have been processed, i.e. bytes from
        // `messagesRead` and any discarded batches.
        private int bytesRead = 0;
        private int messagesRetained = 0;
        private int bytesRetained = 0;
        private long maxOffset = -1L;
        private long maxTimestamp = RecordBatch.NO_TIMESTAMP;
        private long shallowOffsetOfMaxTimestamp = -1L;

        private FilterResult(ByteBuffer outputBuffer) {
            this.outputBuffer = outputBuffer;
        }

        private void updateRetainedBatchMetadata(MutableRecordBatch retainedBatch, int numMessagesInBatch, boolean headerOnly) {
            int bytesRetained = headerOnly ? DefaultRecordBatch.RECORD_BATCH_OVERHEAD : retainedBatch.sizeInBytes();
            updateRetainedBatchMetadata(retainedBatch.maxTimestamp(), retainedBatch.lastOffset(),
                    retainedBatch.lastOffset(), numMessagesInBatch, bytesRetained);
        }

        private void updateRetainedBatchMetadata(long maxTimestamp, long shallowOffsetOfMaxTimestamp, long maxOffset,
                                                 int messagesRetained, int bytesRetained) {
            validateBatchMetadata(maxTimestamp, shallowOffsetOfMaxTimestamp, maxOffset);
            if (maxTimestamp > this.maxTimestamp) {
                this.maxTimestamp = maxTimestamp;
                this.shallowOffsetOfMaxTimestamp = shallowOffsetOfMaxTimestamp;
            }
            this.maxOffset = Math.max(maxOffset, this.maxOffset);
            this.messagesRetained += messagesRetained;
            this.bytesRetained += bytesRetained;
        }

        private void validateBatchMetadata(long maxTimestamp, long shallowOffsetOfMaxTimestamp, long maxOffset) {
            if (maxTimestamp != RecordBatch.NO_TIMESTAMP && shallowOffsetOfMaxTimestamp < 0)
                throw new IllegalArgumentException("shallowOffset undefined for maximum timestamp " + maxTimestamp);
            if (maxOffset < 0)
                throw new IllegalArgumentException("maxOffset undefined");
        }

        /**
         * Return the buffer containing the filtered output.
         *
         * <p>This may be a different buffer than the one originally passed to
         * {@link MemoryRecords#filterTo} if the output grew beyond the destination buffer's
         * capacity and a new, larger buffer was allocated.
         *
         * @return The output buffer; never {@code null}
         */
        public ByteBuffer outputBuffer() {
            return outputBuffer;
        }

        /**
         * Return the total number of records read during the filter pass, including records
         * that were discarded.
         *
         * @return The number of records read
         */
        public int messagesRead() {
            return messagesRead;
        }

        /**
         * Return the total number of bytes read during the filter pass, including bytes from
         * batches that were entirely discarded.
         *
         * @return The number of bytes read
         */
        public int bytesRead() {
            return bytesRead;
        }

        /**
         * Return the number of records written to the output buffer.
         *
         * @return The number of retained records
         */
        public int messagesRetained() {
            return messagesRetained;
        }

        /**
         * Return the number of bytes written to the output buffer.
         *
         * @return The number of retained bytes
         */
        public int bytesRetained() {
            return bytesRetained;
        }

        /**
         * Return the maximum log offset among all retained records.
         *
         * @return The maximum retained offset, or {@code -1} if no records were retained
         */
        public long maxOffset() {
            return maxOffset;
        }

        /**
         * Return the maximum timestamp among all retained records.
         *
         * @return The maximum retained timestamp, or {@link RecordBatch#NO_TIMESTAMP} if no
         *         records with a timestamp were retained
         */
        public long maxTimestamp() {
            return maxTimestamp;
        }

        /**
         * Return the batch-level (shallow) offset of the record with the maximum timestamp.
         *
         * @return The shallow offset of the maximum-timestamp record, or {@code -1} if no
         *         records with a timestamp were retained
         */
        public long shallowOffsetOfMaxTimestamp() {
            return shallowOffsetOfMaxTimestamp;
        }
    }

    /**
     * Wrap an existing {@link ByteBuffer} as a read-only {@code MemoryRecords} instance.
     *
     * <p>The buffer is not copied; the returned instance holds a direct reference to it. The
     * buffer's limit determines the number of bytes that will be iterated. The buffer's
     * position is not modified by this method.
     *
     * @param buffer The buffer containing encoded record batch data; must not be {@code null}
     * @return A new {@code MemoryRecords} backed by the given buffer; never {@code null}
     */
    public static MemoryRecords readableRecords(ByteBuffer buffer) {
        return new MemoryRecords(buffer);
    }

    /**
     * Create a {@link MemoryRecordsBuilder} for the current magic version using the given
     * buffer, compression, timestamp type, and base offset.
     *
     * <p>This is a convenience overload that uses {@link RecordBatch#CURRENT_MAGIC_VALUE} and
     * no producer identity ({@link RecordBatch#NO_PRODUCER_ID}).
     *
     * @param buffer        The destination buffer for the encoded batch data; must not be
     *                      {@code null}
     * @param compression   The compression to apply to the record data; must not be {@code null}
     * @param timestampType The timestamp type for the batch; must not be
     *                      {@link TimestampType#NO_TIMESTAMP_TYPE}
     * @param baseOffset    The base offset of the first record in the batch
     * @return A new {@link MemoryRecordsBuilder}; never {@code null}
     */
    public static MemoryRecordsBuilder builder(ByteBuffer buffer,
                                               Compression compression,
                                               TimestampType timestampType,
                                               long baseOffset) {
        return builder(buffer, RecordBatch.CURRENT_MAGIC_VALUE, compression, timestampType, baseOffset);
    }

    /**
     * Create a {@link MemoryRecordsBuilder} for the current magic version with an explicit
     * maximum size limit.
     *
     * <p>If {@code timestampType} is {@link TimestampType#LOG_APPEND_TIME}, the log-append
     * time is set to the current wall-clock time at the moment this method is called.
     *
     * @param buffer        The destination buffer; must not be {@code null}
     * @param compression   The compression codec; must not be {@code null}
     * @param timestampType The timestamp type; must not be {@code null}
     * @param baseOffset    The base offset of the first record
     * @param maxSize       The maximum number of bytes the builder is allowed to write
     * @return A new {@link MemoryRecordsBuilder}; never {@code null}
     */
    public static MemoryRecordsBuilder builder(ByteBuffer buffer,
                                               Compression compression,
                                               TimestampType timestampType,
                                               long baseOffset,
                                               int maxSize) {
        long logAppendTime = RecordBatch.NO_TIMESTAMP;
        if (timestampType == TimestampType.LOG_APPEND_TIME)
            logAppendTime = System.currentTimeMillis();

        return new MemoryRecordsBuilder(buffer, RecordBatch.CURRENT_MAGIC_VALUE, compression, timestampType, baseOffset,
            logAppendTime, RecordBatch.NO_PRODUCER_ID, RecordBatch.NO_PRODUCER_EPOCH, RecordBatch.NO_SEQUENCE,
            false, false, RecordBatch.NO_PARTITION_LEADER_EPOCH, maxSize);
    }

    /**
     * Create a {@link MemoryRecordsBuilder} with an explicit magic version and log-append time,
     * without producer identity.
     *
     * @param buffer        The destination buffer; must not be {@code null}
     * @param magic         The record format version (magic byte)
     * @param compression   The compression codec; must not be {@code null}
     * @param timestampType The timestamp type; must not be {@code null}
     * @param baseOffset    The base offset of the first record
     * @param logAppendTime The log-append time in milliseconds, or
     *                      {@link RecordBatch#NO_TIMESTAMP} if not applicable
     * @return A new {@link MemoryRecordsBuilder}; never {@code null}
     */
    public static MemoryRecordsBuilder builder(ByteBuffer buffer,
                                               byte magic,
                                               Compression compression,
                                               TimestampType timestampType,
                                               long baseOffset,
                                               long logAppendTime) {
        return builder(buffer, magic, compression, timestampType, baseOffset, logAppendTime,
                RecordBatch.NO_PRODUCER_ID, RecordBatch.NO_PRODUCER_EPOCH, RecordBatch.NO_SEQUENCE, false,
                RecordBatch.NO_PARTITION_LEADER_EPOCH);
    }

    /**
     * Create a {@link MemoryRecordsBuilder} with an explicit magic version, without producer
     * identity.
     *
     * <p>If {@code timestampType} is {@link TimestampType#LOG_APPEND_TIME}, the log-append
     * time is set to the current wall-clock time at the moment this method is called.
     *
     * @param buffer        The destination buffer; must not be {@code null}
     * @param magic         The record format version (magic byte)
     * @param compression   The compression codec; must not be {@code null}
     * @param timestampType The timestamp type; must not be {@code null}
     * @param baseOffset    The base offset of the first record
     * @return A new {@link MemoryRecordsBuilder}; never {@code null}
     */
    public static MemoryRecordsBuilder builder(ByteBuffer buffer,
                                               byte magic,
                                               Compression compression,
                                               TimestampType timestampType,
                                               long baseOffset) {
        long logAppendTime = RecordBatch.NO_TIMESTAMP;
        if (timestampType == TimestampType.LOG_APPEND_TIME)
            logAppendTime = System.currentTimeMillis();
        return builder(buffer, magic, compression, timestampType, baseOffset, logAppendTime,
                RecordBatch.NO_PRODUCER_ID, RecordBatch.NO_PRODUCER_EPOCH, RecordBatch.NO_SEQUENCE, false,
                RecordBatch.NO_PARTITION_LEADER_EPOCH);
    }

    /**
     * Create a {@link MemoryRecordsBuilder} with an explicit magic version, log-append time,
     * and partition leader epoch, without producer identity.
     *
     * @param buffer               The destination buffer; must not be {@code null}
     * @param magic                The record format version (magic byte)
     * @param compression          The compression codec; must not be {@code null}
     * @param timestampType        The timestamp type; must not be {@code null}
     * @param baseOffset           The base offset of the first record
     * @param logAppendTime        The log-append time in milliseconds, or
     *                             {@link RecordBatch#NO_TIMESTAMP} if not applicable
     * @param partitionLeaderEpoch The partition leader epoch, or
     *                             {@link RecordBatch#NO_PARTITION_LEADER_EPOCH} if unknown
     * @return A new {@link MemoryRecordsBuilder}; never {@code null}
     */
    public static MemoryRecordsBuilder builder(ByteBuffer buffer,
                                               byte magic,
                                               Compression compression,
                                               TimestampType timestampType,
                                               long baseOffset,
                                               long logAppendTime,
                                               int partitionLeaderEpoch) {
        return builder(buffer, magic, compression, timestampType, baseOffset, logAppendTime,
                RecordBatch.NO_PRODUCER_ID, RecordBatch.NO_PRODUCER_EPOCH, RecordBatch.NO_SEQUENCE, false, partitionLeaderEpoch);
    }

    /**
     * Create a {@link MemoryRecordsBuilder} for idempotent or transactional producers using
     * the current magic version and {@link TimestampType#CREATE_TIME}.
     *
     * @param buffer          The destination buffer; must not be {@code null}
     * @param compression     The compression codec; must not be {@code null}
