    /**
     * Build a {@code MemoryRecords} containing the given records in a single batch with full
     * control over all batch-level parameters.
     *
     * <p>If {@code records} is empty, {@link #EMPTY} is returned immediately without
     * allocating a buffer.
     *
     * <p><b>Performance note:</b> The buffer size is estimated before encoding begins. If the
     * estimate is too small (e.g., due to compression expanding the data), the underlying
     * {@link ByteBufferOutputStream} will reallocate and copy. For predictable workloads,
     * pre-sizing the buffer via a {@link #builder} overload avoids this reallocation.
     *
     * @param magic                The record format version (magic byte)
     * @param initialOffset        The base offset of the first record
     * @param compression          The compression codec; must not be {@code null}
     * @param timestampType        The timestamp type; must not be {@code null}
     * @param producerId           The producer id, or {@link RecordBatch#NO_PRODUCER_ID} if none
     * @param producerEpoch        The producer epoch, or {@link RecordBatch#NO_PRODUCER_EPOCH}
     *                             if none
     * @param baseSequence         The base sequence number, or {@link RecordBatch#NO_SEQUENCE}
     *                             if none
     * @param partitionLeaderEpoch The partition leader epoch, or
     *                             {@link RecordBatch#NO_PARTITION_LEADER_EPOCH} if unknown
     * @param isTransactional      {@code true} if the batch belongs to a transaction
     * @param records              The records to include; must not be {@code null}
     * @return A new {@code MemoryRecords}, or {@link #EMPTY} if {@code records} is empty;
     *         never {@code null}
     */
    public static MemoryRecords withRecords(byte magic, long initialOffset, Compression compression,
                                            TimestampType timestampType, long producerId, short producerEpoch,
                                            int baseSequence, int partitionLeaderEpoch, boolean isTransactional,
                                            SimpleRecord... records) {
        if (records.length == 0)
            return MemoryRecords.EMPTY;
        int sizeEstimate = AbstractRecords.estimateSizeInBytes(magic, compression.type(), Arrays.asList(records));
        ByteBufferOutputStream bufferStream = new ByteBufferOutputStream(sizeEstimate);
        long logAppendTime = RecordBatch.NO_TIMESTAMP;
        if (timestampType == TimestampType.LOG_APPEND_TIME)
            logAppendTime = System.currentTimeMillis();
        try (final MemoryRecordsBuilder builder = new MemoryRecordsBuilder(bufferStream, magic, compression, timestampType,
                initialOffset, logAppendTime, producerId, producerEpoch, baseSequence, isTransactional, false,
                partitionLeaderEpoch, sizeEstimate)) {
            for (SimpleRecord record : records)
                builder.append(record);
            return builder.build();
        }
    }

