     * {@link VotersRecord}.
     *
     * <p>Voters records describe the current set of KRaft voters and are written to the
     * {@code __cluster_metadata} topic.
     *
     * @param initialOffset The base offset of the control batch
     * @param timestamp     The timestamp to assign to the control record, in milliseconds since
     *                      the Unix epoch
     * @param leaderEpoch   The partition leader epoch
     * @param buffer        The destination buffer; must not be {@code null} and must have
     *                      sufficient remaining capacity
     * @param votersRecord  The voters record to encode; must not be {@code null}
     * @return A new {@code MemoryRecords} containing the control batch; never {@code null}
     */
    public static MemoryRecords withVotersRecord(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        VotersRecord votersRecord
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendVotersMessage(timestamp, votersRecord);
            return builder.build();
        }
    }

    private static MemoryRecordsBuilder createKraftControlRecordBuilder(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer
    ) {
        return new MemoryRecordsBuilder(
            buffer,
            RecordBatch.CURRENT_MAGIC_VALUE,
            Compression.NONE,
            TimestampType.CREATE_TIME,
            initialOffset,
            timestamp,
            RecordBatch.NO_PRODUCER_ID,
            RecordBatch.NO_PRODUCER_EPOCH,
            RecordBatch.NO_SEQUENCE,
            false,
            true,
            leaderEpoch,
            buffer.capacity()
        );
    }
}

